----@class LxAlarmHelper
local LxAlarmHelper = LxClass("LxAlarmHelper", nil)
-----------------------------------------------------------------
local EAlarmTyp = {
    --离线超时
    OFFLINE = 1,
    --准点
    ALARM = 2,
    --创角
    ROLE = 3,
    --挂机奖励
    INSTANCE_BOX = 4,
    --联盟战
    GUILD_BATTLE = 5,
    --联盟首领
    GUILD_BOSS = 6,
    --巅峰对决
    PEAK_AREA = 7,
    --梦见魔泉
    DRAM_FOUNTAIN = 8,
    --女神之争
    CROSS_WAR_INSIDE = 9,
    --萌宠契约赛
    PET_DREAM_LAND_MAIN = 10,
    --圣骑之战
    GUILD_HOLY_BATTLE = 11,
}

-----------------------------------------------------------------

function LxAlarmHelper.InitAlarm()
    if CS.IsOSOpenHarmony() then return end
    
    LxAlarmHelper.RemoveAllAlarm()

    LxAlarmHelper._InnerInitData()
end

function LxAlarmHelper.GetPushSettingList()
    return LxAlarmHelper._settingData
end

function LxAlarmHelper.GetTitleName()
    local appName = LxAlarmHelper._appName
    if not appName then
        appName = LNativeHelper.GetAppName()
        LxAlarmHelper._appName = appName
    end
    return appName or ""
end

function LxAlarmHelper.SetAlarm(pushRef)
    local idx = pushRef.refId
    local pushType = tonumber(pushRef.pushType)
    if not pushType then
        return
    end
    local title = ccLngText(pushRef.name) or ""

    title = string.gsub(title, "#a1", LxAlarmHelper.GetTitleName())

    local content = ccLngText(pushRef.content)
    local pushValue = pushRef.pushValue
    if string.isempty(title) or string.isempty(content) then
        return
    end
    if pushType == EAlarmTyp.ALARM then
        local delayTime = LxAlarmHelper.CalcCurDelayTime(pushValue)
        local repeatTime = 86400
        LNativeHelper.SetRepeatLocalNotification(idx, title, content, delayTime, repeatTime)

    elseif pushType == EAlarmTyp.ROLE then
        local delayTime = LxAlarmHelper.CalcCurDelayTime(pushValue)

        LNativeHelper.SetLocalNotification(idx, title, content, delayTime)

    elseif pushType == EAlarmTyp.OFFLINE then
        local delayTime = (tonumber(pushValue) or 0) * 1000
        LNativeHelper.SetLocalNotification(idx, title, content, delayTime)

    elseif pushType == EAlarmTyp.INSTANCE_BOX then

        if not toboolean(LPlayerPrefs.notifyIdleReward) then
            return
        end

        local nowTime = 0
        if gModelGeneral then
            local time, b2, b3, b4 = gModelGeneral:GetLoginNotifyInfo()
            nowTime = time or 0
        end
        local maxTime = 0
        if gModelInstance then
            maxTime = (gModelInstance:GetBoxTimeLimit() or 0) * 60 + os.time()
        end
        local delayTime = maxTime - nowTime
        if delayTime <= 0 then
            return
        end
        LNativeHelper.SetLocalNotification(idx, title, content, delayTime)

    elseif pushType == EAlarmTyp.GUILD_BATTLE then
        if not toboolean(LPlayerPrefs.notifyGuildBattle) then
            return
        end

        local nowTime = 0
        if gModelGeneral then
            local b1, b2, time, b4 = gModelGeneral:GetLoginNotifyInfo()
            nowTime = time or 0
        end
        local curTime = os.time()
        local delayTime = nowTime - curTime
        if delayTime <= 0 then
            return
        end
        LNativeHelper.SetLocalNotification(idx, title, content, delayTime)

    elseif pushType == EAlarmTyp.GUILD_BOSS then
        if not toboolean(LPlayerPrefs.notifyGuildBoss) then
            return
        end

        local nowTime = 0
        if gModelGeneral then
            local b1, b2, b3, time = gModelGeneral:GetLoginNotifyInfo()
            nowTime = time or 0
        end
        local curTime = os.time()
        local delayTime = nowTime - curTime
        if delayTime <= 0 then
            return
        end
        LNativeHelper.SetLocalNotification(idx, title, content, delayTime)

    elseif pushType == EAlarmTyp.PEAK_AREA then
        if not toboolean(LPlayerPrefs.notifyArenaPeak) then
            return
        end

        local nowTime = 0
        if gModelGeneral then
            local b1, time, b3, b4 = gModelGeneral:GetLoginNotifyInfo()
            nowTime = time or 0
        end
        local curTime = os.time()
        local delayTime = nowTime - curTime
        if delayTime <= 0 then
            return
        end
        LNativeHelper.SetLocalNotification(idx, title, content, delayTime)

    elseif pushType == EAlarmTyp.CROSS_WAR_INSIDE then
        local nowTime = 0
        if gModelGeneral then
            local b1, b2, b3, b4, b5, time = gModelGeneral:GetLoginNotifyInfo()
            nowTime = time or 0
        end
        local curTime = os.time()
        local delayTime = nowTime - curTime
        if delayTime <= 0 then
            return
        end
        LNativeHelper.SetLocalNotification(idx, title, content, delayTime)
    elseif pushType == EAlarmTyp.PET_DREAM_LAND_MAIN then
        local nowTime = 0
        if gModelGeneral then
            local b1, b2, b3, b4, b5, b6, time = gModelGeneral:GetLoginNotifyInfo()
            nowTime = time or 0
        end
        local curTime = os.time()
        local delayTime = nowTime - curTime
        if delayTime <= 0 then
            return
        end
        LNativeHelper.SetLocalNotification(idx, title, content, delayTime)
    elseif pushType == EAlarmTyp.GUILD_HOLY_BATTLE then
        local nowTime = 0
        if gModelGeneral then
            local b1, b2, b3, b4, b5, b6, b7, time = gModelGeneral:GetLoginNotifyInfo()
            nowTime = time or 0
        end
        local curTime = os.time()
        local delayTime = nowTime - curTime
        if delayTime <= 0 then
            return
        end
        LNativeHelper.SetLocalNotification(idx, title, content, delayTime)
    end
end


function LxAlarmHelper._InnerInitData()
    local offlineData = {}
    local settingData = {}

    for k, v in pairs(GameTable.PushMessageRef) do
        if v.refId > 100 then
            table.insert(settingData, v)
            LxAlarmHelper.SetAlarm(v)
        else
            local pushType = tonumber(v.pushType) or 0
            if pushType == EAlarmTyp.OFFLINE then
                table.insert(offlineData, v)
            else
                LxAlarmHelper.SetAlarm(v)
            end
        end
    end

    LxAlarmHelper._offlineData = offlineData
    LxAlarmHelper._settingData = settingData
end

function LxAlarmHelper.CalcTime(timeVal)
    local day = 0
    local hour = 0
    local minute = 0
    local second = 0

    local strArr = string.split(timeVal, "=")
    if not strArr or #strArr == 0 then
        return day, hour, minute, second
    end

    local timeStr = ""
    if #strArr <= 1 then
        timeStr = strArr[1]
    else
        day = tonumber(strArr[1]) or 0 - 1
        if day < 0 then
            day = 0
        end
        timeStr = strArr[2]
    end

    local arrTime = string.split(timeStr, ":")

    if arrTime then
        hour = tonumber(arrTime[1]) or 0
        minute = tonumber(arrTime[2]) or 0
        second = tonumber(arrTime[3]) or 0
    end
    return day, hour, minute, second
end

---当前时间
function LxAlarmHelper.CalcCurDelayTime(timeVal)
    local day, hour, minute, second = LxAlarmHelper.CalcTime(timeVal)

    local curTime = GetTimestamp()
    local timeTbl = LUtil.OSDate("*t", curTime)

    local targetTimeTbl = table.light_copy(timeTbl, {})
    targetTimeTbl.day = timeTbl.day + day
    targetTimeTbl.hour = hour
    targetTimeTbl.min = minute
    targetTimeTbl.sec = second
    local targetTime = LUtil.OSTime(targetTimeTbl)
    local delayTime = targetTime - curTime

    --加一天
    if delayTime < 0 then
        delayTime = delayTime + 86400
    end

    return delayTime
end

function LxAlarmHelper.SetOfflineAlarm()
    local offlineData = LxAlarmHelper._offlineData
    if not offlineData then
        return
    end
    for k, v in ipairs(offlineData) do
        LxAlarmHelper.SetAlarm(v)
    end
end

