function LxAlarmHelper.SetPushAlarm()
    local pushs = {
        { refId = 101, bool = toboolean(LPlayerPrefs.notifyIdleReward) },
        { refId = 102, bool = toboolean(LPlayerPrefs.notifyGuildBattle) },
        { refId = 103, bool = toboolean(LPlayerPrefs.notifyGuildBoss) },
        { refId = 104, bool = toboolean(LPlayerPrefs.notifyArenaPeak) },
        { refId = 105, bool = toboolean(LPlayerPrefs.notifycrossWarTemple) },
        { refId = 106, bool = toboolean(LPlayerPrefs.notifypetDreamLand) },
        { refId = 107, bool = toboolean(LPlayerPrefs.notifyshengqiGuildBattle) },
    }
    for i, v in ipairs(pushs) do
        LxAlarmHelper.DoSetAlarmByRefId(v.bool, v.refId)
    end
end
-----------------------------------------------------------------
function LxAlarmHelper.DoSetAlarmByRefId(bAdd, refId)

    local pushRef = GameTable.PushMessageRef[refId]
    if not pushRef then
        return
    end

    if not bAdd then
        local idx = pushRef.refId
        LNativeHelper.RemoveLocalNotification(idx)
    else
        LxAlarmHelper.SetAlarm(pushRef)
    end
end

function LxAlarmHelper.RemoveAllAlarm()
    if CS.IsOSAndroid() then
        local i = 1
        local max = 5
        for k=i, max do
            LNativeHelper.RemoveLocalNotification(k)
        end
        i = 101
        max = 107
        for k=i, max do
            LNativeHelper.RemoveLocalNotification(k)
        end
    else
        LNativeHelper.RemoveAllLocalNotifications()
    end
end

-----------------------------------------------------------------

return LxAlarmHelper
